document.addEventListener("DOMContentLoaded",function(){var l=document.getElementById("milestoneModal");l&&(l.addEventListener("show.bs.modal",function(m){var d=m.relatedTarget,r=d.getAttribute("data-milestone-id");if(r){var i=document.getElementById(r);if(i){var e=i.closest(".col");if(e){var t=e.cloneNode(!0),a=d.textContent.trim();document.getElementById("milestoneModalLabel").textContent=a||"Milestone Details";var n=document.getElementById("milestoneModalBody");n.innerHTML="",n.appendChild(t);var o=t.querySelector(".card-header");o&&o.remove();return}}}else{var e=d.closest(".col");if(e){var t=e.cloneNode(!0),a=d.textContent.trim();document.getElementById("milestoneModalLabel").textContent=a||"Milestone Details";var n=document.getElementById("milestoneModalBody");n.innerHTML="",n.appendChild(t);var o=t.querySelector(".card-header");o&&o.remove()}}}),l.addEventListener("hidden.bs.modal",function(){document.getElementById("milestoneModalLabel").textContent="",document.getElementById("milestoneModalBody").innerHTML=""}))});
